  type: 'te_reo_usage' | 'tikanga_reference' | 'cultural_sensitivity' | 'iwi_specific' | 'sacred_knowledge';
  severity: 'info' | 'review_needed' | 'iwi_consultation_required';
  description: string;
  recommendation: string;
