/*
 * Assign cultural reviewers by subject from the latest review_queue_*.md
 * Usage: npx tsx scripts/assign-reviewers.ts
 */

import { promises as fs } from 'fs';
import path from 'path';

type ReviewItem = {
  title: string;
  subject: string;
  filePath: string;
};

function mapReviewer(subject: string): string {
  const s = subject.trim();
  switch (s) {
    case 'Social Studies':
      return 'Kaitiaki-Aronui';
    case 'Mathematics':
      return 'Maths-Reviewer';
    case 'Science':
      return 'Science-Reviewer';
    case 'English':
      return 'English-Reviewer';
    case 'Technology':
      return 'Tech-Reviewer';
    default:
      return 'General-Cultural-Reviewer';
  }
}

async function getLatestQueueFile(root: string): Promise<string | null> {
  const dir = path.join(root, 'migration', 'cultural_review');
  let entries: string[] = [];
  try {
    entries = await fs.readdir(dir);
  } catch {
    return null;
  }
  const queues = entries.filter((f) => f.startsWith('review_queue_') && f.endsWith('.md'));
  if (queues.length === 0) return null;
  // Sort by mtime desc
  const withTimes = await Promise.all(
    queues.map(async (f) => {
      const abs = path.join(dir, f);
      const st = await fs.stat(abs);
      return { abs, mtime: st.mtimeMs };
    })
  );
  withTimes.sort((a, b) => b.mtime - a.mtime);
  return withTimes[0].abs;
}

async function parseQueue(filePath: string): Promise<ReviewItem[]> {
  const raw = await fs.readFile(filePath, 'utf-8');
  const lines = raw.split(/\r?\n/);
  const items: ReviewItem[] = [];
  for (let i = 0; i < lines.length; i += 1) {
    const line = lines[i];
    // Example: - [ ] Social Studies Y9 - Civics in Aotearoa (Year: 9, Subject: Social Studies  )
    const m = line.match(/^\- \[ \] (.+?) \(Year:\s*\d+\s*,\s*Subject:\s*([^\)]+)\)/);
    if (m) {
      const title = m[1].trim();
      const subject = m[2].trim();
      // Next lines contain path line starting with "  - Path: "
      let filePathFound = '';
      for (let j = i + 1; j < Math.min(i + 6, lines.length); j += 1) {
        const p = lines[j].trim();
        if (p.startsWith('- Path:')) {
          filePathFound = p.replace(/^- Path:\s*/, '').trim();
          break;
        }
      }
      if (filePathFound) {
        items.push({ title, subject, filePath: filePathFound });
      }
    }
  }
  return items;
}

async function writeAssignments(root: string, items: ReviewItem[]): Promise<string> {
  const assignDir = path.join(root, 'migration', 'cultural_review', 'assignments');
  await fs.mkdir(assignDir, { recursive: true });
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);

  const byReviewer = new Map<string, ReviewItem[]>();
  for (const it of items) {
    const reviewer = mapReviewer(it.subject);
    if (!byReviewer.has(reviewer)) byReviewer.set(reviewer, []);
    byReviewer.get(reviewer)!.push(it);
  }

  const indexPath = path.join(assignDir, `index_${ts}.md`);
  let indexBody = `# Cultural Review Assignment Index\nGenerated: ${new Date().toUTCString()}\n\n`;

  for (const [reviewer, arr] of byReviewer.entries()) {
    const file = path.join(assignDir, `${reviewer}_${ts}.md`);
    let body = `# Cultural Review Assignments - ${reviewer}\nGenerated: ${new Date().toUTCString()}\n\n`;
    for (const it of arr) {
      body += `- [ ] ${it.title}\n  - Path: ${it.filePath}\n  - Subject: ${it.subject}\n  - Notes:\n\n`;
    }
    await fs.writeFile(file, body, 'utf-8');
    indexBody += `- ${reviewer}: ${file}\n`;
  }

  await fs.writeFile(indexPath, indexBody, 'utf-8');
  return indexPath;
}

async function main() {
  const root = process.cwd();
  const latest = await getLatestQueueFile(root);
  if (!latest) {
    console.error('No review_queue_*.md found. Run the review queue generator first.');
    process.exit(1);
  }
  const items = await parseQueue(latest);
  if (items.length === 0) {
    console.log('No items parsed from latest queue:', latest);
    return;
  }
  const indexFile = await writeAssignments(root, items);
  console.log('✅ Assignments generated. Index:', indexFile);
}

main().catch((err) => {
  console.error('assign-reviewers failed:', err);
  process.exit(1);
});

/*
 * Build Resources Script
 * - Scans migration/recovered_resources for markdown files
 * - Copies them to public/resources preserving structure
 * - Generates public/resources/index.json with metadata
 */

import { mkdir, readdir, readFile, stat, writeFile, copyFile } from 'fs/promises';
import path from 'path';

type ResourceIndexEntry = {
  id: string;
  title: string;
  relativePath: string; // path under public/resources
  category: string; // e.g., handouts/assessments
  sizeBytes: number;
  modifiedAt: string;
};

const PROJECT_ROOT = process.cwd();
const SOURCE_ROOT = path.join(PROJECT_ROOT, 'migration', 'recovered_resources');
const PUBLIC_ROOT = path.join(PROJECT_ROOT, 'public');
const DEST_ROOT = path.join(PUBLIC_ROOT, 'resources');

async function ensureDir(dirPath: string): Promise<void> {
  await mkdir(dirPath, { recursive: true });
}

function toId(input: string): string {
  return input
    .toLowerCase()
    .replace(/[^a-z0-9\-\_]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

async function* walk(dir: string, relative = ''): AsyncGenerator<{ abs: string; rel: string }> {
  const entries = await readdir(dir, { withFileTypes: true });
  for (const entry of entries) {
    const abs = path.join(dir, entry.name);
    const rel = path.join(relative, entry.name);
    if (entry.isDirectory()) {
      yield* walk(abs, rel);
    } else {
      yield { abs, rel };
    }
  }
}

async function extractTitleFromMarkdown(absFile: string): Promise<string> {
  try {
    const content = await readFile(absFile, 'utf-8');
    const lines = content.split(/\r?\n/);
    const heading = lines.find(l => l.trim().startsWith('# '));
    return heading ? heading.replace(/^#\s+/, '').trim() : path.basename(absFile);
  } catch {
    return path.basename(absFile);
  }
}

async function buildResources(): Promise<void> {
  await ensureDir(PUBLIC_ROOT);
  await ensureDir(DEST_ROOT);

  const index: ResourceIndexEntry[] = [];

  // Copy markdown files and build index
  try {
    for await (const file of walk(SOURCE_ROOT)) {
      if (!file.rel.toLowerCase().endsWith('.md')) continue;

      const src = file.abs;
      const dst = path.join(DEST_ROOT, file.rel);
      const dstDir = path.dirname(dst);
      await ensureDir(dstDir);
      await copyFile(src, dst);

      const st = await stat(src);
      const title = await extractTitleFromMarkdown(src);

      const relUnderPublic = path.join('resources', file.rel).replaceAll('\\', '/');
      const category = path.dirname(file.rel).split(path.sep)[0] || 'uncategorized';

      index.push({
        id: toId(title || path.basename(file.rel, '.md')),
        title,
        relativePath: relUnderPublic,
        category,
        sizeBytes: st.size,
        modifiedAt: new Date(st.mtimeMs).toISOString()
      });
    }
  } catch (err) {
    console.error('Error while scanning resources:', err);
    throw err;
  }

  // Write index.json
  const indexFile = path.join(DEST_ROOT, 'index.json');
  await writeFile(indexFile, JSON.stringify({ generatedAt: new Date().toISOString(), items: index }, null, 2), 'utf-8');
  console.log(`✅ Resources prepared: ${index.length} items -> ${path.relative(PROJECT_ROOT, indexFile)}`);
}

buildResources().catch(err => {
  console.error('❌ build-resources failed:', err);
  process.exitCode = 1;
});

