    } catch (error) {
      console.error(`❌ Failed to generate ${type}:`, error);
    }
  }
}

// Main execution
async function main() {
  const agent = new DeepSeekAgent();

  console.log('🚀 DeepSeek Content Generator Starting...');
  console.log('🛡️ Cultural safety protocols active');

