        suggestions: ['Run lighthouse audit for detailed performance metrics']
      };
    }
  }
}

/**
 * Accessibility Audit Agent - A11y compliance checks
 */
export class AccessibilityAuditAgent {
  private orchestrator: AIOrchestrator;

  constructor() {
    this.orchestrator = new AIOrchestrator();
  }

  async auditAccessibility(componentFiles: { path: string; content: string }[]): Promise<AuditResult> {
    const prompt = `
You are an accessibility audit agent. Check these React components for a11y issues:

COMPONENTS:
${componentFiles.map(f => `${f.path}:\n${f.content}`).join('\n\n')}

Check for:
1. Missing alt text on images
2. Missing ARIA labels and roles
3. Color contrast issues
4. Keyboard navigation support
5. Focus management
6. Screen reader compatibility
7. Form accessibility

Return JSON with specific accessibility violations and fixes.
    `;

    const result = await this.orchestrator.route({
      type: "accessibility_audit",
      complexity: "simple",
      priority: "speed",
      culturalSensitive: false,
      prompt
    });

    const parsed = this.parseAuditResponse(result);

    return {
      category: 'Accessibility',
      status: parsed.issues.filter(i => i.severity === 'critical' || i.severity === 'high').length > 0 ? 'fail' :
              parsed.issues.length > 0 ? 'warn' : 'pass',
      score: Math.max(0, 100 - (parsed.issues.length * 15)), // A11y is critical
      issues: parsed.issues,
      suggestions: parsed.suggestions,
      timestamp: new Date().toISOString()
    };
  }

  private parseAuditResponse(response: any): { issues: AuditIssue[]; suggestions: string[] } {
    try {
      const jsonMatch = typeof response === 'string' ? response.match(/\{.*\}/s) : null;
      const parsed = jsonMatch ? JSON.parse(jsonMatch[0]) : response;

      return {
        issues: parsed?.issues || [],
        suggestions: parsed?.suggestions || []
      };
    } catch {
      return {
        issues: [{ severity: 'medium', message: 'A11y audit parsing failed - manual review needed' }],
        suggestions: ['Run axe-core or WAVE tool for detailed accessibility audit']
      };
    }
  }
}

/**
 * Audit Orchestrator - Runs all audits and generates comprehensive report
 */
export class AuditOrchestrator {
  private cssAgent: CSSAuditAgent;
  private navAgent: NavigationAuditAgent;
  private perfAgent: PerformanceAuditAgent;
  private a11yAgent: AccessibilityAuditAgent;

  constructor() {
    this.cssAgent = new CSSAuditAgent();
    this.navAgent = new NavigationAuditAgent();
    this.perfAgent = new PerformanceAuditAgent();
    this.a11yAgent = new AccessibilityAuditAgent();
  }

  async runFullAudit(projectFiles: { [category: string]: { path: string; content: string }[] }): Promise<{
    overall: 'pass' | 'warn' | 'fail';
    score: number;
    results: AuditResult[];
    summary: string;
    priority_fixes: string[];
  }> {
    console.log('🔍 Running comprehensive audit with specialized agents...');

    const results: AuditResult[] = [];

    // Run audits in parallel for speed
    const auditPromises = [
      this.cssAgent.auditStyling(projectFiles.styles || []),
      this.navAgent.auditNavigation(projectFiles.navigation || []),
      this.perfAgent.auditPerformance(projectFiles.app || []),
      this.a11yAgent.auditAccessibility(projectFiles.components || [])
    ];

    const auditResults = await Promise.allSettled(auditPromises);

    auditResults.forEach((result, index) => {
      if (result.status === 'fulfilled') {
        results.push(result.value);
      } else {
        const categories = ['CSS/Styling', 'Navigation/UX', 'Performance', 'Accessibility'];
        results.push({
          category: categories[index],
          status: 'fail',
          score: 0,
          issues: [{ severity: 'critical', message: `Audit failed: ${result.reason}` }],
          suggestions: ['Fix audit system'],
          timestamp: new Date().toISOString()
        });
      }
    });

    // Calculate overall score and status
    const overallScore = results.reduce((sum, r) => sum + r.score, 0) / results.length;
    const criticalIssues = results.flatMap(r => r.issues.filter(i => i.severity === 'critical'));
    const highIssues = results.flatMap(r => r.issues.filter(i => i.severity === 'high'));

    const overall = criticalIssues.length > 0 ? 'fail' : 
                   highIssues.length > 2 ? 'warn' : 'pass';

    // Generate priority fixes
    const priorityFixes = [
      ...criticalIssues.slice(0, 3).map(i => `CRITICAL: ${i.message}`),
      ...highIssues.slice(0, 3).map(i => `HIGH: ${i.message}`)
    ];

    const summary = this.generateSummary(results, overallScore, overall);

    console.log(`✅ Audit complete - Overall status: ${overall} (${overallScore.toFixed(0)}/100)`);

    return {
      overall,
      score: overallScore,
      results,
      summary,
      priority_fixes: priorityFixes
    };
  }

  private generateSummary(results: AuditResult[], score: number, status: string): string {
    const totalIssues = results.reduce((sum, r) => sum + r.issues.length, 0);
    const passCount = results.filter(r => r.status === 'pass').length;

    return `
Audit Summary (${score.toFixed(0)}/100 - ${status.toUpperCase()}):
- ${passCount}/${results.length} categories passed
- ${totalIssues} total issues found
- Categories: ${results.map(r => `${r.category} (${r.status})`).join(', ')}

${status === 'fail' ? '🚨 Critical issues need immediate attention' : 
  status === 'warn' ? '⚠️ Some improvements recommended' : 
  '✅ All audits passed - great work!'}
    `.trim();
  }
}

/**
 * Quick audit runner for immediate feedback
 */
export async function runQuickAudit(files: { path: string; content: string }[]): Promise<void> {
  const cssFiles = files.filter(f => f.path.includes('.css') || f.path.includes('style'));
  const componentFiles = files.filter(f => f.path.includes('.tsx') || f.path.includes('.jsx'));

  const orchestrator = new AuditOrchestrator();

  const auditResult = await orchestrator.runFullAudit({
    styles: cssFiles,
    navigation: componentFiles.filter(f => f.path.includes('Nav') || f.path.includes('nav')),
    app: componentFiles,
    components: componentFiles
  });

  console.log('\n📊 QUICK AUDIT RESULTS');
  console.log('═══════════════════════');
  console.log(auditResult.summary);

  if (auditResult.priority_fixes.length > 0) {
    console.log('\n🔧 PRIORITY FIXES:');
    auditResult.priority_fixes.forEach(fix => console.log(`  • ${fix}`));
  }

  console.log('\n💡 Run full audit for detailed breakdown');
}

// src/ai/orchestrator.ts
import { AIRegistry } from "./registry";
import { writeEpisode } from "./provenance";

type TaskPriority = "speed" | "depth" | "reliability" | "cost";
type TaskComplexity = "simple" | "medium" | "complex" | "critical";

export class AIOrchestrator {
  private registry: AIRegistry;

  constructor() {
    this.registry = new AIRegistry();
  }

  /**
   * Claude (me) as the intelligent router and fallback coordinator
   */
  async route(task: {
    type: string;
    complexity: TaskComplexity;
    priority: TaskPriority;
    culturalSensitive?: boolean;
    prompt: string;
    context?: any;
  }) {

    // CRITICAL RULE: Claude can always handle everything as backup
    const fallbackToClaude = {
      llm: this.registry.getProvider("windsurf-claude"),
      model: "claude-3-5-sonnet-20241022",
      reason: "fallback_orchestrator"
    };

    try {
      // Route based on task characteristics
      const routing = this.determineRouting(task);

      // Try primary choice first
      try {
        const result = await routing.primary.llm?.generate?.(task.prompt, { 
          model: routing.primary.model,
          temperature: this.getTemperatureForTask(task),
          maxTokens: this.getTokenLimitForTask(task)
        });

        await this.logSuccess(task, routing.primary, result);
        return result;

      } catch (primaryError) {
        console.warn(`Primary choice failed (${routing.primary.reason}):`, primaryError);

        // Claude steps in as intelligent backup
        const result = await fallbackToClaude.llm?.generate?.(
          this.wrapPromptForClaudeOrchestration(task.prompt, task, primaryError),
          { model: fallbackToClaude.model }
        );

        await this.logFallback(task, routing.primary, fallbackToClaude, result, primaryError);
        return result;
      }

    } catch (routingError) {
      // If routing itself fails, Claude handles everything
      console.error("Routing failed, Claude taking over:", routingError);

      const result = await fallbackToClaude.llm?.generate?.(
        this.wrapPromptForClaudeOrchestration(task.prompt, task, routingError),
        { model: fallbackToClaude.model }
      );

      await this.logEmergencyFallback(task, result, routingError);
      return result;
    }
  }

  private determineRouting(task: any) {
    // Gemini for multimodal content - images, videos, mixed media lesson plans
    if (task.type.includes("multimodal") || task.type.includes("visual") || task.context?.hasMedia) {
      return {
        primary: { 
          llm: this.registry.getProvider("gemini-cli"), 
          model: "gemini-1.5-pro",
          reason: "multimodal_processing_required"
        }
      };
    }

    // DeepSeek for heavy reasoning and mathematical content
    if (task.complexity === "complex" && (task.priority === "depth" || task.type.includes("math"))) {
      return {
        primary: { 
          llm: this.registry.getProvider("deepseek"), 
          model: "deepseek-reasoner",
          reason: "complex_reasoning_required"
        }
      };
    }

    // Gemini for creative lesson design and gamification (good at creative tasks)
    if (task.type.includes("creative") || task.type.includes("game") || task.type.includes("interactive")) {
      return {
        primary: { 
          llm: this.registry.getProvider("gemini-cli"), 
          model: "gemini-1.5-flash",
          reason: "creative_and_interactive_content"
        }
      };
    }

    // GPT for fast, simple tasks and embeddings
    if (task.complexity === "simple" && task.priority === "speed") {
      return {
        primary: { 
          llm: this.registry.getProvider("openai"), 
          model: "gpt-4o-mini",
          reason: "speed_optimized"
        }
      };
    }

    // Claude for cultural sensitivity, critical tasks, orchestration, or when reliability is key
    if (task.culturalSensitive || task.complexity === "critical" || task.priority === "reliability") {
      return {
        primary: { 
          llm: this.registry.getProvider("windsurf-claude"), 
          model: "claude-3-5-sonnet-20241022",
          reason: "cultural_safety_and_reliability"
        }
      };
    }

    // Default: Claude orchestrates everything else
    return {
      primary: { 
        llm: this.registry.getProvider("windsurf-claude"), 
        model: "claude-3-5-sonnet-20241022",
        reason: "default_orchestrator"
      }
    };
  }

  /**
   * When Claude steps in as backup, give it full context about what failed and why
   */
  private wrapPromptForClaudeOrchestration(originalPrompt: string, task: any, error: any) {
    return `
You are the TeAoMarama orchestrator stepping in as backup. The primary agent failed.

CONTEXT:
- Task: ${task.type}
- Complexity: ${task.complexity}
- Priority: ${task.priority}
- Cultural sensitive: ${task.culturalSensitive || false}
- Error: ${error?.message || 'Unknown failure'}

ORIGINAL PROMPT:
${originalPrompt}

Handle this with your full capabilities, considering the failure context and ensuring reliability.
    `;
  }

  private async logSuccess(task: any, routing: any, result: any) {
    await writeEpisode("orchestrator", {
      timestamp: new Date().toISOString(),
      agent: `agent:${routing.llm?.name || 'unknown'}`,
      action: "orchestrated_success",
      context: {
        task_type: task.type,
        complexity: task.complexity,
        priority: task.priority,
        tokens: result?.tokensOut,
        latency: result?.latencyMs
      },
      result: result
    });
  }

  private async logFallback(task: any, failed: any, backup: any, result: any, error: any) {
    await writeEpisode("orchestrator", {
      timestamp: new Date().toISOString(),
      agent: `agent:${backup.llm?.name || 'unknown'}`,
      action: "orchestrated_fallback",
      context: {
        task_type: task.type,
        failed_provider: failed.llm?.name,
        failure_reason: error?.message,
        backup_success: true,
        tokens: result?.tokensOut
      },
      result: result
    });
  }

  private async logEmergencyFallback(task: any, _result: any, error: any) {
    await writeEpisode("orchestrator", {
      timestamp: new Date().toISOString(),
      agent: "agent:claude",
      action: "emergency_orchestration",
      context: {
        task_type: task.type,
        system_failure: true,
        error: error?.message
      }
    });
  }

  private getTemperatureForTask(task: any): number {
    if (task.type.includes("extract") || task.type.includes("critic")) return 0.1;
    if (task.type.includes("creative") || task.type.includes("lesson")) return 0.7;
    return 0.3;
  }

  private getTokenLimitForTask(task: any): number {
    if (task.complexity === "complex") return 4000;
    if (task.complexity === "critical") return 8000;
    return 1500;
  }
}

