// src/ai/provenance.ts
export interface EpisodeData {
  timestamp: string;
  agent: string;
  action: string;
  context: any;
  result?: any;
  culturalFlags?: string[];
  quality?: number;
}

export interface ProvenanceChain {
  id: string;
  episodes: EpisodeData[];
  created: string;
  lastUpdated: string;
}

class ProvenanceManager {
  private chains: Map<string, ProvenanceChain> = new Map();

  createChain(id: string): ProvenanceChain {
    const chain: ProvenanceChain = {
      id,
      episodes: [],
      created: new Date().toISOString(),
      lastUpdated: new Date().toISOString()
    };
    this.chains.set(id, chain);
    return chain;
  }

  getChain(id: string): ProvenanceChain | undefined {
    return this.chains.get(id);
  }

  addEpisode(chainId: string, episode: EpisodeData): void {
    const chain = this.chains.get(chainId);
    if (chain) {
      chain.episodes.push(episode);
      chain.lastUpdated = new Date().toISOString();
    }
  }
}

const manager = new ProvenanceManager();

export async function writeEpisode(chainId: string, episode: EpisodeData): Promise<void> {
  // Ensure chain exists
  if (!manager.getChain(chainId)) {
    manager.createChain(chainId);
  }

  manager.addEpisode(chainId, episode);

  // In the future, could write to file or database
  console.log(`[PROVENANCE] ${episode.agent}: ${episode.action}`, episode);
}

export function getProvenanceChain(chainId: string): ProvenanceChain | undefined {
  return manager.getChain(chainId);
}

export function getAllChains(): ProvenanceChain[] {
  return Array.from((manager as any).chains.values());
}

// src/ai/registry.ts
export interface AIProvider {
  name: string;
  apiKey?: string;
  baseURL?: string;
  model?: string;
  available: boolean;
  generate?: (prompt: string, options?: any) => Promise<any>;
}

export interface AICapability {
  name: string;
  description: string;
  providers: string[];
  cost: number;
  speed: number;
  quality: number;
}

export class AIRegistry {
  private providers: Map<string, AIProvider> = new Map();
  private capabilities: Map<string, AICapability> = new Map();

  constructor() {
    this.initializeDefaults();
  }

  private initializeDefaults() {
    // Kaitiaki Mahara (VS Code Copilot)
    this.registerProvider({
      name: "kaitiaki-mahara",
      available: true,
      model: "gpt-4",
      generate: async (prompt: string) => ({ text: `[MAHARA]: ${prompt}` })
    });

    // GPT5 (Cascade)
    this.registerProvider({
      name: "gpt5-cascade",
      available: true,
      model: "gpt-5",
      generate: async (prompt: string) => ({ text: `[GPT5]: ${prompt}` })
    });

    // Windsurf Claude (Me)
    this.registerProvider({
      name: "windsurf-claude",
      available: true,
      model: "claude-sonnet-4",
      generate: async (prompt: string) => ({ text: `[CLAUDE]: ${prompt}` })
    });

    // DeepSeek
    this.registerProvider({
      name: "deepseek",
      available: false,
      model: "deepseek-coder",
      generate: async (prompt: string) => ({ text: `[DEEPSEEK]: ${prompt}` })
    });

    // Exa.ai
    this.registerProvider({
      name: "exa",
      available: false,
      model: "exa-search",
      generate: async (prompt: string) => ({ text: `[EXA]: ${prompt}` })
    });
  }

  registerProvider(provider: AIProvider): void {
    this.providers.set(provider.name, provider);
  }

  getProvider(name: string): AIProvider | undefined {
    return this.providers.get(name);
  }

  getAllProviders(): AIProvider[] {
    return Array.from(this.providers.values());
  }

  getAvailableProviders(): AIProvider[] {
    return this.getAllProviders().filter(p => p.available);
  }

  registerCapability(capability: AICapability): void {
    this.capabilities.set(capability.name, capability);
  }

  getCapability(name: string): AICapability | undefined {
    return this.capabilities.get(name);
  }

  getBestProviderForTask(taskType: string): AIProvider | undefined {
    const capability = this.getCapability(taskType);
    if (!capability) return undefined;

    const availableProviders = capability.providers
      .map(name => this.getProvider(name))
      .filter(p => p && p.available);

    return availableProviders[0]; // Simple selection for now
  }
}

