                  className={`p-2 ${viewMode === 'grid' ? 'bg-blue-50 text-blue-600' : 'text-gray-500'}`}
                >
                  <Grid className="w-5 h-5" />
                </button>
                <button
                  onClick={() => setViewMode('list')}
                  className={`p-2 ${viewMode === 'list' ? 'bg-blue-50 text-blue-600' : 'text-gray-500'}`}
                >
                  <List className="w-5 h-5" />
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Resources Grid */}
        <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-semibold text-gray-900">
              Teaching Resources ({filteredResources.length})
            </h2>
            <button className="text-sm text-blue-600 hover:text-blue-700 font-medium">
              View all →
            </button>
          </div>

          {filteredResources.length > 0 ? (
            <div className={`grid gap-6 ${
              viewMode === 'grid' 
                ? 'grid-cols-1 md:grid-cols-2 lg:grid-cols-3' 
                : 'grid-cols-1'
            }`}>
              {filteredResources.map(resource => (
                <ResourceCard key={resource.id} resource={resource} />
              ))}
            </div>
          ) : (
            <div className="text-center py-12">
              <BookOpen className="mx-auto h-12 w-12 text-gray-400 mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">No resources found</h3>
              <p className="text-gray-500">Try adjusting your search or filters</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import { MetadataParser, type ParsedResource } from '../services/MetadataParser';

export default function Resources() {
  const [resources, setResources] = useState<ParsedResource[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Filters
  const [query, setQuery] = useState('');
  const [category, setCategory] = useState<string>('all');
  const [subject, setSubject] = useState<string>('all');
  const [yearLevel, setYearLevel] = useState<string>('all');
  const [safety, setSafety] = useState<'all' | 'clean' | 'review' | 'consultation'>('all');

  useEffect(() => {
    async function load() {
      try {
        const parsed = await MetadataParser.parseResourcesFromIndex('/resources/index.json');
        setResources(parsed);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load resources');
      } finally {
        setLoading(false);
      }
    }
    load();
  }, []);

  const categories = useMemo(
    () => ['all', ...Array.from(new Set(resources.map(r => r.category)))],
    [resources]
  );
  const subjects = useMemo(
    () => ['all', ...Array.from(new Set(resources.map(r => r.metadata.subject)))],
    [resources]
  );
  const years = useMemo(
    () => ['all', ...Array.from(new Set(resources.map(r => r.metadata.yearLevel)))],
    [resources]
  );

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    return resources.filter(r => {
      if (category !== 'all' && r.category !== category) return false;
      if (subject !== 'all' && r.metadata.subject !== subject) return false;
      if (yearLevel !== 'all' && r.metadata.yearLevel !== yearLevel) return false;
      if (safety !== 'all' && r.metadata.culturalSafetyLevel !== safety) return false;
      if (!q) return true;
      return (
        r.searchableText?.includes?.(q) ||
        r.title.toLowerCase().includes(q) ||
        r.relativePath.toLowerCase().includes(q)
      );
    });
  }, [resources, query, category, subject, yearLevel, safety]);

  return (
    <div className="max-w-7xl mx-auto px-4 py-10">
      <h1 className="text-3xl font-bold mb-2">Educational Resources</h1>
      <p className="text-gray-600 mb-6">Browse {resources.length.toLocaleString()} items. Use search and filters to narrow down.</p>

      {/* Controls */}
      <div className="bg-white border rounded-lg p-4 mb-8 grid gap-3 md:grid-cols-5">
        <input
          value={query}
          onChange={e => setQuery(e.target.value)}
          placeholder="Search by title, content, tags…"
          className="md:col-span-2 border rounded px-3 py-2"
        />
        <select value={category} onChange={e => setCategory(e.target.value)} className="border rounded px-3 py-2">
          {categories.map(c => (
            <option key={c} value={c}>{c === 'all' ? 'All categories' : c}</option>
          ))}
        </select>
        <select value={subject} onChange={e => setSubject(e.target.value)} className="border rounded px-3 py-2">
          {subjects.map(s => (
            <option key={s} value={s}>{s === 'all' ? 'All subjects' : s}</option>
          ))}
        </select>
        <div className="flex gap-2">
          <select value={yearLevel} onChange={e => setYearLevel(e.target.value)} className="flex-1 border rounded px-3 py-2">
            {years.map(y => (
              <option key={y} value={y}>{y === 'all' ? 'All years' : y}</option>
            ))}
          </select>
          <select value={safety} onChange={e => setSafety(e.target.value as any)} className="flex-1 border rounded px-3 py-2">
            <option value="all">All safety</option>
            <option value="clean">🟢 Clean</option>
            <option value="review">🟡 Review</option>
            <option value="consultation">🔴 Consultation</option>
          </select>
        </div>
      </div>

      {loading && <p>Loading resources…</p>}
      {error && <p className="text-red-600">{error}</p>}
      {!loading && !error && (
        <>
          <div className="text-sm text-gray-600 mb-4">Showing {filtered.length.toLocaleString()} result(s)</div>
          <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
            {filtered.map(item => (
              <Link
                key={item.id}
                to={`/resource?path=${encodeURIComponent(item.relativePath)}`}
                className="block border rounded-lg p-4 hover:border-indigo-400 hover:shadow-md transition"
              >
                <div className="flex items-center justify-between text-xs text-gray-500 mb-2">
                  <span>{new Date(item.modifiedAt).toLocaleDateString()}</span>
                  <span>{(item.sizeBytes/1024).toFixed(1)} KB</span>
                </div>
                <div className="font-semibold text-indigo-700 mb-1">{item.title}</div>
                <div className="text-xs text-gray-600 mb-2 flex gap-2 flex-wrap">
                  <span className="px-2 py-0.5 bg-gray-100 rounded">{item.metadata.subject}</span>
                  <span className="px-2 py-0.5 bg-gray-100 rounded">{item.metadata.yearLevel}</span>
                  <span className="px-2 py-0.5 bg-gray-100 rounded">{item.metadata.culturalSafetyIcon} {item.metadata.culturalSafetyLevel}</span>
                </div>
                {item.preview && (
                  <div className="text-sm text-gray-700 line-clamp-3">{item.preview}</div>
                )}
              </Link>
            ))}
          </div>
        </>
      )}
    </div>
  );
}

/**
 * Enhanced Resources Page - Scalable for Thousands of Educational Resources
 * 
 * Features:
 * - Hierarchical navigation: Subject Areas > Unit Plans > Lesson Plans > Resources
 * - Beautiful Te Kete Ako design system integration
 * - Performance optimized for massive datasets
 * - Advanced filtering and search capabilities
 * - Responsive design for all screen sizes
 * - Cultural safety indicators and content curation
 */

import { useState, useEffect, useMemo, useCallback } from 'react';
import { Link } from 'react-router-dom';
import { MetadataParser, type ParsedResource } from '../services/MetadataParser';

// Types for hierarchical content organization
interface SubjectArea {
  name: string;
  description: string;
  icon: string;
  color: string;
  unitPlans: UnitPlan[];
  totalResources: number;
}

interface UnitPlan {
  id: string;
  title: string;
  description: string;
  yearLevel: string;
  duration: string;
  lessonPlans: LessonPlan[];
  nzcAlignment: string[];
  culturalContext: boolean;
}

interface LessonPlan {
  id: string;
  title: string;
  description: string;
  duration: string;
  resources: ResourceItem[];
  learningObjectives: string[];
  culturalAlignment: boolean;
}

interface ResourceItem {
  id: string;
  title: string;
  type: 'handout' | 'activity' | 'video' | 'game' | 'slideshow' | 'link' | 'assessment';
  url: string;
  description: string;
  culturalSafetyLevel: 'clean' | 'review' | 'consultation';
  fileSize?: number;
  duration?: string;
  preview?: string;
}

type ViewMode = 'hierarchy' | 'grid' | 'list' | 'cards';
type FilterMode = 'all' | 'culturally-aligned' | 'nzc-mapped' | 'recent';

export default function ResourcesEnhanced() {
  // State management
  const [resources, setResources] = useState<ParsedResource[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Navigation state
  const [viewMode, setViewMode] = useState<ViewMode>('hierarchy');
  const [selectedSubject, setSelectedSubject] = useState<string | null>(null);
  const [selectedUnit, setSelectedUnit] = useState<string | null>(null);
  const [selectedLesson, setSelectedLesson] = useState<string | null>(null);

  // Filter state
  const [searchQuery, setSearchQuery] = useState('');
  const [filterMode, setFilterMode] = useState<FilterMode>('all');
  const [yearLevelFilter, setYearLevelFilter] = useState<string>('all');
  const [safetyFilter, setSafetyFilter] = useState<string>('all');

  // UI state
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [showPreview, setShowPreview] = useState<string | null>(null);

  // Load resources
  useEffect(() => {
    async function loadResources() {
      try {
        const parsed = await MetadataParser.parseResourcesFromIndex('/resources/index.json');
        setResources(parsed);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Failed to load resources');
      } finally {
        setLoading(false);
      }
    }
    loadResources();
  }, []);

  // Transform flat resources into hierarchical structure
  const subjectAreas = useMemo(() => {
    const subjects: Record<string, SubjectArea> = {};

    resources.forEach(resource => {
      const subject = resource.metadata.subject || 'General';

      if (!subjects[subject]) {
        subjects[subject] = {
          name: subject,
          description: getSubjectDescription(subject),
          icon: getSubjectIcon(subject),
          color: getSubjectColor(subject),
          unitPlans: [],
          totalResources: 0
        };
      }

      subjects[subject].totalResources++;

      // Group by unit plans (simplified for demo)
      // In real implementation, this would be based on resource metadata
    });

    return Object.values(subjects);
  }, [resources]);

  // Filter resources based on current filters
  const filteredResources = useMemo(() => {
    let filtered = resources;

    // Apply search query
    if (searchQuery.trim()) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter(r => 
        r.title.toLowerCase().includes(query) ||
        r.searchableText?.toLowerCase().includes(query) ||
        r.metadata.subject?.toLowerCase().includes(query)
      );
    }

    // Apply filter mode
    switch (filterMode) {
      case 'culturally-aligned':
        filtered = filtered.filter(r => r.metadata.culturalSafetyLevel === 'clean');
        break;
      case 'nzc-mapped':
        filtered = filtered.filter(r => r.metadata.nzcAlignment && r.metadata.nzcAlignment.length > 0);
        break;
      case 'recent':
        filtered = filtered.filter(r => {
          const modDate = new Date(r.modifiedAt);
          const weekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
          return modDate > weekAgo;
        });
        break;
    }

    // Apply year level filter
    if (yearLevelFilter !== 'all') {
      filtered = filtered.filter(r => r.metadata.yearLevel === yearLevelFilter);
    }

    // Apply safety filter
    if (safetyFilter !== 'all') {
      filtered = filtered.filter(r => r.metadata.culturalSafetyLevel === safetyFilter);
    }

    return filtered;
  }, [resources, searchQuery, filterMode, yearLevelFilter, safetyFilter]);

  const breadcrumbs = useMemo(() => {
    const crumbs: Array<{ label: string; path: string | null }> = [{ label: 'All Subjects', path: null }];
    if (selectedSubject) {
      crumbs.push({ label: selectedSubject, path: selectedSubject });
    }
    if (selectedUnit) {
      crumbs.push({ label: selectedUnit, path: `${selectedSubject}/${selectedUnit}` });
    }
    if (selectedLesson) {
      crumbs.push({ label: selectedLesson, path: `${selectedSubject}/${selectedUnit}/${selectedLesson}` });
    }
    return crumbs;
  }, [selectedSubject, selectedUnit, selectedLesson]);

  if (loading) return <LoadingSkeleton />;
  if (error) return <ErrorDisplay error={error} />;

  return (
    <div className="min-h-screen" style={{ backgroundColor: 'var(--color-bg)' }}>
      {/* Enhanced Header */}
      <header className="sticky top-0 z-50 border-b" style={{ 
        backgroundColor: 'var(--color-white)',
        borderColor: 'var(--color-border)',
        boxShadow: 'var(--shadow-light)'
      }}>
        <div className="container-wide px-6 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-4">
              <button
                onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
                className="p-2 rounded-lg transition-colors lg:hidden"
                style={{ 
                  backgroundColor: 'var(--color-neutral-100)',
                  color: 'var(--color-primary)'
                }}
              >
                ☰
              </button>

              <div>
                <h1 className="text-2xl font-bold" style={{ color: 'var(--color-primary)' }}>
                  Te Kete Ako Resources
                </h1>
                <p className="text-sm" style={{ color: 'var(--color-neutral-700)' }}>
                  {filteredResources.length.toLocaleString()} resources • {subjectAreas.length} subject areas
                </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              {/* View Mode Selector */}
              <div className="flex rounded-lg border" style={{ borderColor: 'var(--color-border)' }}>
                {(['hierarchy', 'grid', 'list', 'cards'] as ViewMode[]).map((mode) => (
                  <button
                    key={mode}
                    onClick={() => setViewMode(mode)}
                    className={`px-3 py-2 text-sm font-medium transition-colors ${
                      viewMode === mode ? 'text-white' : 'text-gray-700 hover:text-white'
                    }`}
                    style={{
                      backgroundColor: viewMode === mode ? 'var(--color-pounamu)' : 'transparent'
                    }}
                  >
                    {mode === 'hierarchy' ? '🌳' : mode === 'grid' ? '⊞' : mode === 'list' ? '☰' : '📋'}
                  </button>
                ))}
              </div>

              <button className="px-4 py-2 rounded-lg font-medium transition-all" style={{
                backgroundColor: 'var(--color-kowhai)',
                color: 'white'
              }}>
                ➕ Add Resource
              </button>
            </div>
          </div>

          {/* Breadcrumb Navigation */}
          {breadcrumbs.length > 1 && (
            <nav className="flex items-center gap-2 mt-4 text-sm">
              {breadcrumbs.map((crumb, index) => (
                <div key={index} className="flex items-center gap-2">
                  {index > 0 && <span style={{ color: 'var(--color-neutral-500)' }}>→</span>}
                  <button
                    onClick={() => {
                      if (index === 0) {
                        setSelectedSubject(null);
                        setSelectedUnit(null);
                        setSelectedLesson(null);
                      } else if (index === 1) {
                        setSelectedUnit(null);
                        setSelectedLesson(null);
                      } else if (index === 2) {
                        setSelectedLesson(null);
                      }
                    }}
                    className={`transition-colors ${
                      index === breadcrumbs.length - 1 
                        ? 'font-medium' 
                        : 'hover:underline'
                    }`}
                    style={{ 
                      color: index === breadcrumbs.length - 1 
                        ? 'var(--color-primary)' 
                        : 'var(--color-pounamu)'
                    }}
                  >
                    {crumb.label}
                  </button>
                </div>
              ))}
            </nav>
          )}
        </div>
      </header>

      <div className="flex">
        {/* Advanced Sidebar */}
        <aside className={`fixed lg:sticky top-0 h-screen transition-all duration-300 z-40 ${
          sidebarCollapsed ? 'w-0 lg:w-16' : 'w-80'
        }`} style={{ 
          backgroundColor: 'var(--color-white)',
          borderRight: '1px solid var(--color-border)'
        }}>
          <div className={`p-6 h-full overflow-y-auto ${sidebarCollapsed && 'lg:px-2'}`}>
            {!sidebarCollapsed && (
              <>
                {/* Search */}
                <div className="mb-6">
                  <input
                    type="text"
                    placeholder="Search resources, units, lessons..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full px-4 py-3 rounded-lg border transition-colors"
                    style={{ 
                      borderColor: 'var(--color-border)',
                      backgroundColor: 'var(--color-neutral-50)'
                    }}
                  />
                </div>

                {/* Quick Filters */}
                <div className="mb-6">
                  <h3 className="font-semibold mb-3" style={{ color: 'var(--color-primary)' }}>
                    Quick Filters
                  </h3>
                  <div className="space-y-2">
                    {([
                      { key: 'all', label: '📚 All Resources', count: resources.length },
                      { key: 'culturally-aligned', label: '🌿 Culturally Aligned', count: resources.filter(r => r.metadata.culturalSafetyLevel === 'clean').length },
                      { key: 'nzc-mapped', label: '🎯 NZC Mapped', count: resources.filter(r => r.metadata.nzcAlignment?.length).length },
                      { key: 'recent', label: '🆕 Recently Added', count: resources.filter(r => new Date(r.modifiedAt) > new Date(Date.now() - 7 * 24 * 60 * 60 * 1000)).length }
                    ] as const).map((filter) => (
                      <button
                        key={filter.key}
                        onClick={() => setFilterMode(filter.key)}
                        className={`w-full flex items-center justify-between p-3 rounded-lg transition-all ${
                          filterMode === filter.key ? 'text-white' : 'text-gray-700 hover:bg-gray-50'
                        }`}
                        style={{
                          backgroundColor: filterMode === filter.key ? 'var(--color-pounamu)' : 'transparent'
                        }}
                      >
                        <span className="font-medium">{filter.label}</span>
                        <span className="text-sm opacity-75">{filter.count}</span>
                      </button>
                    ))}
                  </div>
                </div>

                {/* Year Level Filter */}
                <div className="mb-6">
                  <h3 className="font-semibold mb-3" style={{ color: 'var(--color-primary)' }}>
                    Year Level
                  </h3>
                  <select
                    value={yearLevelFilter}
                    onChange={(e) => setYearLevelFilter(e.target.value)}
                    className="w-full px-3 py-2 rounded-lg border"
                    style={{ borderColor: 'var(--color-border)' }}
                  >
                    <option value="all">All Year Levels</option>
                    {['Y1', 'Y2', 'Y3', 'Y4', 'Y5', 'Y6', 'Y7', 'Y8', 'Y9', 'Y10', 'Y11', 'Y12', 'Y13'].map(year => (
                      <option key={year} value={year}>{year}</option>
                    ))}
                  </select>
                </div>

                {/* Cultural Safety Filter */}
                <div className="mb-6">
                  <h3 className="font-semibold mb-3" style={{ color: 'var(--color-primary)' }}>
                    Cultural Safety
                  </h3>
                  <select
                    value={safetyFilter}
                    onChange={(e) => setSafetyFilter(e.target.value)}
                    className="w-full px-3 py-2 rounded-lg border"
                    style={{ borderColor: 'var(--color-border)' }}
                  >
                    <option value="all">All Safety Levels</option>
                    <option value="clean">🟢 Clean (Ready to Use)</option>
                    <option value="review">🟡 Needs Review</option>
                    <option value="consultation">🔴 Requires Consultation</option>
                  </select>
                </div>
              </>
            )}
          </div>
        </aside>

        {/* Main Content Area */}
        <main className={`flex-1 transition-all duration-300 ${
          sidebarCollapsed ? 'lg:ml-16' : 'ml-0 lg:ml-80'
        }`}>
          <div className="p-6">
            {viewMode === 'hierarchy' && !selectedSubject && (
              <SubjectAreasView
                subjects={subjectAreas}
                onSelectSubject={setSelectedSubject}
              />
            )}

            {viewMode === 'hierarchy' && selectedSubject && !selectedUnit && (
              <UnitPlansView
                subjectName={selectedSubject}
                resources={filteredResources.filter(r => r.metadata.subject === selectedSubject)}
                onSelectUnit={setSelectedUnit}
                onBack={() => setSelectedSubject(null)}
              />
            )}

            {viewMode === 'hierarchy' && selectedUnit && !selectedLesson && (
              <LessonPlansView
                unitName={selectedUnit}
                resources={filteredResources}
                onSelectLesson={setSelectedLesson}
                onBack={() => setSelectedUnit(null)}
              />
            )}

            {viewMode === 'hierarchy' && selectedLesson && (
              <ResourcesDetailView
                lessonName={selectedLesson}
                resources={filteredResources}
                onBack={() => setSelectedLesson(null)}
              />
            )}

            {viewMode === 'grid' && (
              <GridView resources={filteredResources} />
            )}

            {viewMode === 'list' && (
              <ListView resources={filteredResources} />
            )}

            {viewMode === 'cards' && (
              <CardsView resources={filteredResources} />
            )}
          </div>
        </main>
      </div>
    </div>
  );
}

